namespace sv_372950fbbfad46aaa98619a0b8dc2390.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var stepNumber = i + 1;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var cssClass = isCurrent ? "step current" : isCompleted ? "step completed" : "step future";

            <li class="@cssClass">
                @if (isCompleted && !isCurrent)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-icon">&#10003;</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <span class="step-content">
                        <span class="step-icon">@stepNumber</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </span>
                }
            </li>

            @if (i < StepNames.Count - 1)
            {
                <li class="step-connector @(isCompleted ? "completed" : "")" aria-hidden="true"></li>
            }
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    };
}

@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" value="@FullName" @onchange="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
        @if (_errors.ContainsKey("FullName"))
        {
            <span class="field-error">@_errors["FullName"]</span>
        }
    </div>

    <div class="form-group">
        <label for="email">Email *</label>
        <input id="email" type="email" value="@Email" @onchange="e => EmailChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
        @if (_errors.ContainsKey("Email"))
        {
            <span class="field-error">@_errors["Email"]</span>
        }
    </div>

    <div class="form-group">
        <label for="phone">Phone *</label>
        <input id="phone" type="tel" value="@Phone" @onchange="e => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
        @if (_errors.ContainsKey("Phone"))
        {
            <span class="field-error">@_errors["Phone"]</span>
        }
    </div>

    <div class="form-group">
        <label for="address">Address *</label>
        <textarea id="address" rows="2" @onchange="e => AddressChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Address</textarea>
        @if (_errors.ContainsKey("Address"))
        {
            <span class="field-error">@_errors["Address"]</span>
        }
    </div>

    @if (!string.IsNullOrEmpty(_generalError))
    {
        <div class="form-error">@_generalError</div>
    }

    <div class="step-actions">
        <button class="btn-primary" @onclick="HandleNext" disabled="@_isValidating">
            @(_isValidating ? "Validating..." : "Next")
        </button>
    </div>
</section>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> EmailChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> AddressChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private string _generalError = "";
    private bool _isValidating;

    private async Task HandleNext()
    {
        _errors.Clear();
        _generalError = "";

        if (string.IsNullOrWhiteSpace(FullName))
            _errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            _errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            _errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            _errors["Address"] = "Address is required.";

        if (_errors.Count > 0) return;

        _isValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Email);
            if (!emailValid)
            {
                _errors["Email"] = "Email address is not valid.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        catch
        {
            _generalError = "An error occurred validating your email. Please try again.";
        }
        finally
        {
            _isValidating = false;
        }
    }
}

@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<fieldset class="work-entry">
    <legend>Position @(Index + 1)</legend>

    <div class="form-group">
        <label>Company *</label>
        <input type="text" value="@Company" @onchange="e => CompanyChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Title" @onchange="e => TitleChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@StartDate.ToString("yyyy-MM-dd")" @onchange="HandleStartDateChanged" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@(EndDate?.ToString("yyyy-MM-dd") ?? "")" disabled="@IsCurrent" @onchange="HandleEndDateChanged" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="HandleIsCurrentChanged" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" @onchange="e => DescriptionChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Description</textarea>
    </div>

    @if (CanRemove)
    {
        <button type="button" class="btn-danger" @onclick="OnRemove">Remove</button>
    }
</fieldset>

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime StartDate { get; set; } = DateTime.Today;
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool CanRemove { get; set; }

    [Parameter, EditorRequired] public EventCallback<string> CompanyChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> TitleChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<DateTime> StartDateChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<DateTime?> EndDateChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<bool> IsCurrentChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> DescriptionChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnRemove { get; set; }

    private void HandleStartDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
            StartDateChanged.InvokeAsync(date);
    }

    private void HandleEndDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
            EndDateChanged.InvokeAsync(date);
        else
            EndDateChanged.InvokeAsync(null);
    }

    private void HandleIsCurrentChanged(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        IsCurrentChanged.InvokeAsync(isCurrent);
    }
}

@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        var entry = Entries[index];

        <WorkEntryForm Index="index"
                       Company="@entry.Company"
                       Title="@entry.Title"
                       StartDate="@entry.StartDate"
                       EndDate="@entry.EndDate"
                       IsCurrent="@entry.IsCurrent"
                       Description="@entry.Description"
                       CanRemove="@(Entries.Count > 1)"
                       CompanyChanged="@(v => UpdateEntry(index, entry with { Company = v }))"
                       TitleChanged="@(v => UpdateEntry(index, entry with { Title = v }))"
                       StartDateChanged="@(v => UpdateEntry(index, entry with { StartDate = v }))"
                       EndDateChanged="@(v => UpdateEntry(index, entry with { EndDate = v }))"
                       IsCurrentChanged="@(v => UpdateEntry(index, entry with { IsCurrent = v, EndDate = v ? null : entry.EndDate }))"
                       DescriptionChanged="@(v => UpdateEntry(index, entry with { Description = v }))"
                       OnRemove="@(() => RemoveEntry(index))" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="form-error">@_error</div>
    }

    <div class="step-actions">
        <button class="btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string _error = "";

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        var list = new List<WorkEntryModel>(Entries);
        list[index] = updated;
        EntriesChanged.InvokeAsync(list);
    }

    private void AddEntry()
    {
        var list = new List<WorkEntryModel>(Entries) { new() };
        EntriesChanged.InvokeAsync(list);
    }

    private void RemoveEntry(int index)
    {
        var list = new List<WorkEntryModel>(Entries);
        list.RemoveAt(index);
        EntriesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        _error = "";
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                _error = "Each position requires at least a company name and job title.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

