@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section">
    <h2>References</h2>
    <p class="step-description">Please provide 2–3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        var reference = References[index];

        <ReferenceForm Index="index"
                       Name="@reference.Name"
                       Relationship="@reference.Relationship"
                       Email="@reference.Email"
                       Phone="@reference.Phone"
                       CanRemove="@(References.Count > 2)"
                       NameChanged="@(v => UpdateRef(index, reference with { Name = v }))"
                       RelationshipChanged="@(v => UpdateRef(index, reference with { Relationship = v }))"
                       EmailChanged="@(v => UpdateRef(index, reference with { Email = v }))"
                       PhoneChanged="@(v => UpdateRef(index, reference with { Phone = v }))"
                       OnRemove="@(() => RemoveRef(index))" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="form-error">@_error</div>
    }

    <div class="step-actions">
        <button class="btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string _error = "";

    private void UpdateRef(int index, ReferenceModel updated)
    {
        var list = new List<ReferenceModel>(References);
        list[index] = updated;
        ReferencesChanged.InvokeAsync(list);
    }

    private void AddReference()
    {
        if (References.Count >= 3) return;
        var list = new List<ReferenceModel>(References) { new() };
        ReferencesChanged.InvokeAsync(list);
    }

    private void RemoveRef(int index)
    {
        var list = new List<ReferenceModel>(References);
        list.RemoveAt(index);
        ReferencesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        _error = "";
        if (References.Count < 2)
        {
            _error = "Please provide at least 2 references.";
            return;
        }
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                _error = "All reference fields are required.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label for="coverLetter">Write your cover letter below:</label>
        <textarea id="coverLetter" rows="12" maxlength="@MaxLength"
                  @oninput="HandleInput"
                  value="@CoverLetter"></textarea>
        <span class="char-count">@CoverLetter.Length / @MaxLength characters</span>
    </div>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="form-error">@_error</div>
    }

    <div class="step-actions">
        <button class="btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string _error = "";

    private void HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        if (value.Length > MaxLength)
            value = value[..MaxLength];
        CoverLetterChanged.InvokeAsync(value);
    }

    private async Task HandleNext()
    {
        _error = "";
        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            _error = "Please write a cover letter before proceeding.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section review-section">
    <h2>Review & Submit</h2>

    @if (_submitted)
    {
        <div class="confirmation">
            <h3>&#10003; Application Submitted Successfully!</h3>
            <p>Your application ID is: <strong>@_applicationId</strong></p>
            <p>Thank you for applying. We will be in touch.</p>
        </div>
    }
    else
    {
        <div class="review-block">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@FullName</dd>
                <dt>Email</dt><dd>@Email</dd>
                <dt>Phone</dt><dd>@Phone</dd>
                <dt>Address</dt><dd>@Address</dd>
            </dl>
        </div>

        <div class="review-block">
            <div class="review-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-item">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="date-range">
