@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> EmailChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> AddressChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private string _generalError = "";
    private bool _isValidating;

    private async Task HandleNext()
    {
        _errors.Clear();
        _generalError = "";

        if (string.IsNullOrWhiteSpace(FullName))
            _errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            _errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            _errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            _errors["Address"] = "Address is required.";

        if (_errors.Count > 0) return;

        _isValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Email);
            if (!emailValid)
            {
                _errors["Email"] = "Email address is not valid.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        catch
        {
            _generalError = "An error occurred validating your email. Please try again.";
        }
        finally
        {
            _isValidating = false;
        }
    }
}

