    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" value="@FullName" @onchange="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
        @if (_errors.ContainsKey("FullName"))
