{"path": "/tmp/sv-372950fbbfad46aaa98619a0b8dc2390/Components/Pages/Apply/ReviewStep.razor", "file_text": "@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section review-section">
    <h2>Review & Submit</h2>

    @if (_submitted)
    {
        <div class="confirmation">
            <h3>&#10003; Application Submitted Successfully!</h3>
            <p>Your application ID is: <strong>@_applicationId</strong></p>
            <p>Thank you for applying. We will be in touch.</p>
        </div>
    }
    else
    {
        <div class="review-block">
            <div class="review-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Name</dt><dd>@FullName</dd>
                <dt>Email</dt><dd>@Email</dd>
                <dt>Phone</dt><dd>@Phone</dd>
                <dt>Address</dt><dd>@Address</dd>
            </dl>
        </div>

        <div class="review-block">
            <div class="review-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-item">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="date-range">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-block">
            <div class="review-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var reference in References)
            {
                <div class="review-item">
                    <strong>@reference.Name</strong> (@reference.Relationship)
                    <br />@reference.Email | @reference.Phone
                </div>
            }
        </div>

        <div class="review-block">
            <div class="review-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </div>

        @if (!string.IsNullOrEmpty(_error))
        {
            <div class="form-error">@_error</div>
        }

        <div class="step-actions">
            <button class="btn-secondary" @onclick="OnBack">Back</button>
            <button class="btn-primary" @onclick="HandleSubmit" disabled="@_isSubmitting">
                @(_isSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</section>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> SubmitApplication { get; set; } = default!;

    private bool _isSubmitting;
    private bool _submitted;
    private int _applicationId;
    private string _error = "";

    private async Task HandleSubmit()
    {
        _error = "";
        _isSubmitting = true;
        try
        {
            _applicationId = await SubmitApplication();
            _submitted = true;
        }
        catch
        {
            _error = "An error occurred while submitting your application. Please try again.";
        }
        finally
        {
            _isSubmitting = false;
        }
    }
}
"}

