@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" value="@FullName" @onchange="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
        @if (_errors.ContainsKey("FullName"))
        {
            <span class="field-error">@_errors["FullName"]</span>
        }
    </div>

    <div class="form-group">
        <label for="email">Email *</label>
        <input id="email" type="email" value="@Email" @onchange="e => EmailChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
        @if (_errors.ContainsKey("Email"))
        {
            <span class="field-error">@_errors["Email"]</span>
        }
    </div>

    <div class="form-group">
        <label for="phone">Phone *</label>
        <input id="phone" type="tel" value="@Phone" @onchange="e => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
        @if (_errors.ContainsKey("Phone"))
        {
            <span class="field-error">@_errors["Phone"]</span>
        }
    </div>

    <div class="form-group">
        <label for="address">Address *</label>
        <textarea id="address" rows="2" @onchange="e => AddressChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Address</textarea>
        @if (_errors.ContainsKey("Address"))
        {
            <span class="field-error">@_errors["Address"]</span>
        }
    </div>

    @if (!string.IsNullOrEmpty(_generalError))
    {
        <div class="form-error">@_generalError</div>
    }

    <div class="step-actions">
        <button class="btn-primary" @onclick="HandleNext" disabled="@_isValidating">
            @(_isValidating ? "Validating..." : "Next")
        </button>
    </div>
</section>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> EmailChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> AddressChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private string _generalError = "";
    private bool _isValidating;

    private async Task HandleNext()
    {
        _errors.Clear();
        _generalError = "";

        if (string.IsNullOrWhiteSpace(FullName))
            _errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            _errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            _errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            _errors["Address"] = "Address is required.";

        if (_errors.Count > 0) return;

        _isValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Email);
            if (!emailValid)
            {
                _errors["Email"] = "Email address is not valid.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        catch
        {
            _generalError = "An error occurred validating your email. Please try again.";
        }
        finally
        {
            _isValidating = false;
        }
    }
}

