@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var stepNumber = i + 1;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var cssClass = isCurrent ? "step current" : isCompleted ? "step completed" : "step future";

            <li class="@cssClass">
                @if (isCompleted && !isCurrent)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-icon">&#10003;</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <span class="step-content">
                        <span class="step-icon">@stepNumber</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </span>
                }
            </li>

            @if (i < StepNames.Count - 1)
            {
                <li class="step-connector @(isCompleted ? "completed" : "")" aria-hidden="true"></li>
            }
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    };
}

