@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<fieldset class="work-entry">
    <legend>Position @(Index + 1)</legend>

    <div class="form-group">
        <label>Company *</label>
        <input type="text" value="@Company" @onchange="e => CompanyChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Title" @onchange="e => TitleChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@StartDate.ToString("yyyy-MM-dd")" @onchange="HandleStartDateChanged" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@(EndDate?.ToString("yyyy-MM-dd") ?? "")" disabled="@IsCurrent" @onchange="HandleEndDateChanged" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="HandleIsCurrentChanged" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" @onchange="e => DescriptionChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Description</textarea>
    </div>

    @if (CanRemove)
    {
        <button type="button" class="btn-danger" @onclick="OnRemove">Remove</button>
    }
</fieldset>

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime StartDate { get; set; } = DateTime.Today;
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool CanRemove { get; set; }

    [Parameter, EditorRequired] public EventCallback<string> CompanyChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> TitleChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<DateTime> StartDateChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<DateTime?> EndDateChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<bool> IsCurrentChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> DescriptionChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnRemove { get; set; }

    private void HandleStartDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
            StartDateChanged.InvokeAsync(date);
    }

    private void HandleEndDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
            EndDateChanged.InvokeAsync(date);
        else
            EndDateChanged.InvokeAsync(null);
    }

    private void HandleIsCurrentChanged(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        IsCurrentChanged.InvokeAsync(isCurrent);
    }
}

