@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply

<section class="step-section">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        var entry = Entries[index];

        <WorkEntryForm Index="index"
                       Company="@entry.Company"
                       Title="@entry.Title"
                       StartDate="@entry.StartDate"
                       EndDate="@entry.EndDate"
                       IsCurrent="@entry.IsCurrent"
                       Description="@entry.Description"
                       CanRemove="@(Entries.Count > 1)"
                       CompanyChanged="@(v => UpdateEntry(index, entry with { Company = v }))"
                       TitleChanged="@(v => UpdateEntry(index, entry with { Title = v }))"
                       StartDateChanged="@(v => UpdateEntry(index, entry with { StartDate = v }))"
                       EndDateChanged="@(v => UpdateEntry(index, entry with { EndDate = v }))"
                       IsCurrentChanged="@(v => UpdateEntry(index, entry with { IsCurrent = v, EndDate = v ? null : entry.EndDate }))"
                       DescriptionChanged="@(v => UpdateEntry(index, entry with { Description = v }))"
                       OnRemove="@(() => RemoveEntry(index))" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(_error))
    {
        <div class="form-error">@_error</div>
    }

    <div class="step-actions">
        <button class="btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string _error = "";

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        var list = new List<WorkEntryModel>(Entries);
        list[index] = updated;
        EntriesChanged.InvokeAsync(list);
    }

    private void AddEntry()
    {
        var list = new List<WorkEntryModel>(Entries) { new() };
        EntriesChanged.InvokeAsync(list);
    }

    private void RemoveEntry(int index)
    {
        var list = new List<WorkEntryModel>(Entries);
        list.RemoveAt(index);
        EntriesChanged.InvokeAsync(list);
    }

    private async Task HandleNext()
    {
        _error = "";
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                _error = "Each position requires at least a company name and job title.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }
}

