+    private void UpdateRef(int index, ReferenceModel updated)
+    {
+        var list = new List<ReferenceModel>(References);
+        list[index] = updated;
+        ReferencesChanged.InvokeAsync(list);
+    }
+
+    private void AddReference()
+    {
+        if (References.Count >= 3) return;
+        var list = new List<ReferenceModel>(References) { new() };
+        ReferencesChanged.InvokeAsync(list);
+    }
+
+    private void RemoveRef(int index)
+    {
+        var list = new List<ReferenceModel>(References);
+        list.RemoveAt(index);
+        ReferencesChanged.InvokeAsync(list);
+    }
+
+    private async Task HandleNext()
+    {
+        _error = "";
+        if (References.Count < 2)
+        {
+            _error = "Please provide at least 2 references.";
+            return;
+        }
+        foreach (var r in References)
+        {
+            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
+                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
+            {
+                _error = "All reference fields are required.";
+                return;
+            }
+        }
+        await OnNext.InvokeAsync();
+    }
+}
