@page "/apply"
@rendermode InteractiveServer
@namespace sv_372950fbbfad46aaa98619a0b8dc2390.Components.Pages.Apply
@using sv_372950fbbfad46aaa98619a0b8dc2390.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@_fullName"
                              Email="@_email"
                              Phone="@_phone"
                              Address="@_address"
                              FullNameChanged="@(v => _fullName = v)"
                              EmailChanged="@(v => _email = v)"
                              PhoneChanged="@(v => _phone = v)"
                              AddressChanged="@(v => _address = v)"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep Entries="_workEntries"
                             EntriesChanged="@(v => _workEntries = v)"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep References="_references"
                            ReferencesChanged="@(v => _references = v)"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@_coverLetter"
                             CoverLetterChanged="@(v => _coverLetter = v)"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep FullName="@_fullName"
                        Email="@_email"
                        Phone="@_phone"
                        Address="@_address"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="@_coverLetter"
                        OnBack="PreviousStep"
                        OnEditStep="GoToStep"
                        SubmitApplication="SubmitAsync" />
            break;
    }
</div>

@code {
    private int _currentStep;
    private HashSet<int> _completedSteps = new();

    // Step 1 state
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 state
    private List<WorkEntryModel> _workEntries = new() { new() };

    // Step 3 state
    private List<ReferenceModel> _references = new() { new(), new() };

    // Step 4 state
    private string _coverLetter = "";

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        _currentStep++;
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step) || step == _currentStep)
            _currentStep = step;
    }

    private async Task<int> SubmitAsync()
    {
        var personal = new PersonalInfo(_fullName, _email, _phone, _address);
        var workEntries = _workEntries.Select(e =>
            new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList();
        var work = new WorkHistory(workEntries);
        var refs = _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();

        var application = new JobApplication(personal, work, refs, _coverLetter);
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

